VALUES
  ('judicial-57f41407-moex-00333', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於委任契約，下列敘述何者錯誤？', '["委任契約無論是否定有期限，當事人均可任意終止", "非可歸責於受任人之事由，於受任人處理委任事務未完畢前而委任契約已終止者，受任人就其已處理之 部分不得請求報酬", "原則上受任人要服從指示，不可隨意變更委任人之指示", "原則上受任人要親自處理委任事務，不可隨意將委任事務委由第三人代為處理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00334', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '刑事訴訟中被告委任辯護之律師，為獲知卷證內容，不得以下列何種方式為之？', '["檢閱", "抄錄", "攝影", "帶回卷宗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00335', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '依實務見解，法院或檢察官訊問證人時，如未踐行刑事訴訟法第186條第2項告知證人有拒絕證言權，則 因此所取得之證人證詞，對於本案被告證據能力有無之認定，下列敘述何者正確？', '["由事實審法院在個案中任意決定", "法院應適用刑事訴訟法第158條之4規定權衡判斷證人證言之證據能力有無", "證人依法具結之證言當然有證據能力", "證人於此情況下所為之具結不生效力，無證據能力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00336', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '偵查中之羈押審查程序，經檢察官請求法院禁止被告及其辯護人獲知之卷證資料，下列敘述何者正確？', '["基於偵查不公開原則，雖可作為羈押審查之依據，但不得讓被告及其辯護人獲知其內容", "是否作為羈押審查之依據，應審酌人權保障及公共利益之均衡維護判斷之", "是否作為羈押審查之依據，由法院依職權審酌之", "不得作為羈押審查之依據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00337', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '司法警察自下午開始詢問被告，因專注問案且案情繁雜，直至夜間始詢問完畢，已逾日落後 10 分鐘，剛 好被告於該段逾時期間內出於自由意志自白犯罪，倘無准於夜間詢問之例外規定，下列敘述何者正確？', '["被告自白雖出於自由意志而為，但司法警察已違反不得夜間詢問之規定，不得作為證據", "司法警察雖違反不得夜間詢問之規定，但被告自白只要經法院合法調查，仍可作為證據", "司法警察雖違反不得夜間詢問之規定，但並非出於惡意，且被告自白係出於自由意志而為，又與事實相 符，自可作為證據", "除法律另有規定外，由法院於個案中權衡認定被告自白是否可作為證據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00338', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於緘默權之敘述，何者正確？', '["檢察官訊問被告之前，不必告知被告有緘默權", "被告之緘默權是來自不自證己罪之特權", "司法警察官詢問犯罪嫌疑人之前，不必告知犯罪嫌疑人有緘默權", "法官訊問被告之前，不必告知被告有緘默權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00339', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於刑事責任，下列敘述何者錯誤？', '["行為人有精神障礙或其他心智缺陷，免除其刑", "瘖啞人之行為，得減輕其刑", "業務上之正當行為，不罰", "依法令之行為，不罰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00340', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於刑法上阻卻違法事由之敘述，何者錯誤？', '["依法令之行為，不罰", "業務上之正當行為，不罰", "對於現在不法之侵害，防衛行為過當者，不罰", "得被害人承諾所為之普通傷害行為，不罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00341', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲將車輛停在市政府所規劃之收費停車格內睡覺，仍被市政府委託予民間之停車收費員乙開立停車單，甲 心生不滿，於乙開單時毆打乙，甲之行為如何評價？', '["乙為授權公務員，故甲構成妨害公務罪", "乙為受託公務員，故甲構成妨害公務罪", "乙雖為受託公務員，但不是依法執行職務，故甲不構成妨害公務罪", "乙不是公務員，故甲只成立傷害罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00342', 'judicial-57f41407', 'judicial-57f41407-moex-113-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '警員甲明知A於其轄區內經營遊藝場，並有與顧客對賭之賭博行為，某日得知上級指派任務將於當日晚上 至A之遊藝場臨檢，於是透過其女友乙將上開勤務訊息轉知A，使A得以逃避查緝。依實務見解，下列 關於甲、乙刑事責任之敘述，何者正確？', '["甲、乙均不成立犯罪", "甲不成立犯罪，乙成立洩漏國防以外之秘密罪", "甲成立洩漏國防以外之秘密罪，乙不成立犯罪", "甲、乙均成立洩漏國防以外之秘密罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "50ffcc7000b9", "answer_pdf_sha1": "462a4b66839b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0312", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
